import React, { useState, useEffect } from "react";
import {
  FaEnvelope,
  FaPhone,
  FaMapMarkerAlt,
  FaEdit,
  FaSave,
} from "react-icons/fa";
import { AiOutlineClose } from "react-icons/ai";

const Profile = () => {
  const [isEditing, setIsEditing] = useState(false);
  const [profile, setProfile] = useState({
    name: "",
    email: "",
    phone: "",
    location: "",
    bio: "",
    skills: [],
  });

  /* Load user from localStorage */
  useEffect(() => {
    const storedUser = JSON.parse(localStorage.getItem("user"));
    if (storedUser) {
      setProfile({
        name: storedUser.name || "User",
        email: storedUser.email || "",
        phone: storedUser.phone || "",
        location: storedUser.location || "",
        bio: storedUser.bio || "No bio added",
        skills: storedUser.skills || [],
      });
    }
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setProfile((prev) => ({ ...prev, [name]: value }));
  };

  const handleSave = () => {
    setIsEditing(false);

    // 🔴 Later connect API here
    localStorage.setItem(
      "user",
      JSON.stringify({ ...JSON.parse(localStorage.getItem("user")), ...profile })
    );
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <div className="rounded-xl bg-white shadow-lg p-6">
        {/* HEADER */}
        <div className="flex items-center gap-4 mb-6">
          <div className="flex h-14 w-14 items-center justify-center rounded-full bg-indigo-500 text-white text-2xl font-bold">
            {profile.name?.charAt(0)}
          </div>
          <div>
            <h2 className="text-xl font-semibold">{profile.name}</h2>
            <p className="text-gray-500 text-sm">{profile.bio}</p>
          </div>
        </div>

        {/* DETAILS */}
        <div className="space-y-4">
          {/* EMAIL */}
          <div className="flex items-center gap-3">
            <FaEnvelope className="text-gray-400" />
            {isEditing ? (
              <input
                type="email"
                name="email"
                value={profile.email}
                onChange={handleChange}
                className="w-full rounded-md border px-3 py-1"
              />
            ) : (
              <p>{profile.email}</p>
            )}
          </div>

          {/* PHONE */}
          <div className="flex items-center gap-3">
            <FaPhone className="text-gray-400" />
            {isEditing ? (
              <input
                type="text"
                name="phone"
                value={profile.phone}
                onChange={handleChange}
                className="w-full rounded-md border px-3 py-1"
              />
            ) : (
              <p>{profile.phone || "Not provided"}</p>
            )}
          </div>

          {/* LOCATION */}
          <div className="flex items-center gap-3">
            <FaMapMarkerAlt className="text-gray-400" />
            {isEditing ? (
              <input
                type="text"
                name="location"
                value={profile.location}
                onChange={handleChange}
                className="w-full rounded-md border px-3 py-1"
              />
            ) : (
              <p>{profile.location || "Not provided"}</p>
            )}
          </div>
        </div>

        {/* SKILLS */}
        <div className="mt-6">
          <h4 className="font-semibold mb-2">Skills</h4>
          <div className="flex flex-wrap gap-2">
            {profile.skills.length > 0 ? (
              profile.skills.map((skill, i) => (
                <span
                  key={i}
                  className="rounded-full bg-indigo-100 px-3 py-1 text-sm text-indigo-700"
                >
                  {skill}
                </span>
              ))
            ) : (
              <p className="text-gray-500 text-sm">No skills added</p>
            )}
          </div>
        </div>

        {/* ACTION BUTTONS */}
        <div className="mt-8 flex gap-3">
          {isEditing ? (
            <>
              <button
                onClick={handleSave}
                className="flex items-center gap-2 rounded-md bg-indigo-600 px-4 py-2 text-white hover:bg-indigo-700"
              >
                <FaSave /> Save
              </button>
              <button
                onClick={() => setIsEditing(false)}
                className="flex items-center gap-2 rounded-md bg-gray-500 px-4 py-2 text-white hover:bg-gray-600"
              >
                <AiOutlineClose /> Cancel
              </button>
            </>
          ) : (
            <button
              onClick={() => setIsEditing(true)}
              className="flex items-center gap-2 rounded-md bg-green-600 px-4 py-2 text-white hover:bg-green-700"
            >
              <FaEdit /> Edit Profile
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default Profile;
